INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('3e297630-05fc-48a6-886f-3f9fdfdeccf6', 'Collocation ''Urban sprawl'' (Sự bành trướng đô thị) miêu tả hiện tượng gì?', 'multiple_choice', '["Sự phát triển các công viên cây xanh trong thành phố.","Sự lan rộng nhanh chóng và mất kiểm soát của các khu vực đô thị ra các vùng nông thôn xung quanh.","Việc xây dựng nhà chọc trời.","Việc cấm xe cộ vào trung tâm."]', 'Sự lan rộng nhanh chóng và mất kiểm soát của các khu vực đô thị ra các vùng nông thôn xung quanh.', 'Urban sprawl là hệ quả tiêu cực của Overpopulation (bùng nổ dân số), gây tắc nghẽn giao thông và phá hủy đất nông nghiệp.'),
('3e297630-05fc-48a6-886f-3f9fdfdeccf6', 'Sự hòa nhập và bị đồng hóa văn hóa của người nhập cư vào quốc gia sở tại được gọi là gì?', 'multiple_choice', '["Cultural heritage.","Cultural assimilation.","Culture shock.","Cultural isolation."]', 'Cultural assimilation.', 'Assimilation (sự đồng hóa) là khi người thiểu số từ bỏ bản sắc riêng để thích nghi hoàn toàn với văn hóa dòng chính.'),
('3e297630-05fc-48a6-886f-3f9fdfdeccf6', 'Khái niệm ''Social mobility'' (Sự dịch chuyển xã hội) đề cập đến khả năng gì của một cá nhân?', 'multiple_choice', '["Khả năng đi du lịch nhiều nước.","Khả năng vươn lên thay đổi tầng lớp, vị thế kinh tế - xã hội của mình nhờ vào năng lực và giáo dục.","Khả năng sử dụng mạng xã hội.","Khả năng giao tiếp đa ngôn ngữ."]', 'Khả năng vươn lên thay đổi tầng lớp, vị thế kinh tế - xã hội của mình nhờ vào năng lực và giáo dục.', 'Một xã hội công bằng là xã hội có ''high social mobility'', nơi con nhà nghèo vẫn có thể trở thành tỷ phú.'),
('11acf6ae-8a36-4204-a6f9-ca990d7e017e', 'Hiện tượng ''Inflation'' (Lạm phát) ảnh hưởng thế nào đến nền kinh tế?', 'multiple_choice', '["Làm cho mọi thứ trở nên miễn phí.","Sự gia tăng liên tục của mức giá chung, dẫn đến sự suy giảm sức mua của đồng tiền (tiền mất giá).","Sự gia tăng giá trị của đồng tiền.","Sự kết thúc của thương mại quốc tế."]', 'Sự gia tăng liên tục của mức giá chung, dẫn đến sự suy giảm sức mua của đồng tiền (tiền mất giá).', 'Inflation là kẻ thù của ''Cost of living'' (chi phí sinh hoạt). Lạm phát cao khiến cuộc sống của người dân khó khăn hơn.'),
('11acf6ae-8a36-4204-a6f9-ca990d7e017e', 'Chỉ số GDP (Gross Domestic Product) dùng để đo lường điều gì?', 'multiple_choice', '["Tổng số lượng dân cư của một quốc gia.","Tổng sản phẩm quốc nội: giá trị thị trường của tất cả hàng hóa và dịch vụ được sản xuất ra trong một quốc gia.","Số tiền nợ của chính phủ.","Tỷ lệ người thất nghiệp."]', 'Tổng sản phẩm quốc nội: giá trị thị trường của tất cả hàng hóa và dịch vụ được sản xuất ra trong một quốc gia.', 'GDP là thước đo quy mô và sức khỏe kinh tế của một quốc gia.'),
('11acf6ae-8a36-4204-a6f9-ca990d7e017e', 'Thuật ngữ ''Cost of living'' (Chi phí sinh hoạt) có nghĩa là gì?', 'multiple_choice', '["Số tiền để mua một ngôi nhà.","Số tiền trung bình cần thiết để trang trải các nhu cầu cơ bản như thức ăn, nhà ở, y tế và quần áo tại một khu vực nhất định.","Thuế thu nhập cá nhân.","Số tiền tiết kiệm được trong một năm."]', 'Số tiền trung bình cần thiết để trang trải các nhu cầu cơ bản như thức ăn, nhà ở, y tế và quần áo tại một khu vực nhất định.', '''High cost of living'' (Chi phí sinh hoạt đắt đỏ) là bất lợi lớn nhất khi sống ở các ''metropolises'' (siêu đô thị).'),
('6b8b49d0-895c-4fc2-ac2e-c0d5ce7d6658', 'Thuật ngữ ''Juvenile delinquency'' dùng để chỉ loại tội phạm nào?', 'multiple_choice', '["Tội phạm công nghệ cao.","Hành vi phạm pháp do trẻ vị thành niên, thanh thiếu niên gây ra.","Tội phạm giết người hàng loạt.","Hành vi trốn thuế của doanh nghiệp."]', 'Hành vi phạm pháp do trẻ vị thành niên, thanh thiếu niên gây ra.', 'Đây là topic cực kỳ quen thuộc trong Writing Task 2. Nguyên nhân thường do ''lack of parental supervision'' (thiếu sự quản lý của cha mẹ).'),
('6b8b49d0-895c-4fc2-ac2e-c0d5ce7d6658', 'Mục đích của việc áp dụng các hình phạt nghiêm khắc như một ''Deterrent'' là gì?', 'multiple_choice', '["Để trả thù tội phạm.","Để tạo ra sự răn đe, ngăn chặn tội phạm tương lai vì sợ hãi hậu quả.","Để lấy tiền nộp phạt xây đường.","Để giáo dục lại người phạm tội."]', 'Để tạo ra sự răn đe, ngăn chặn tội phạm tương lai vì sợ hãi hậu quả.', 'Danh từ ''Deterrent'' (sự răn đe) là mục tiêu cốt lõi của hệ thống pháp luật (Legal system) để duy trì trật tự xã hội.'),
('6b8b49d0-895c-4fc2-ac2e-c0d5ce7d6658', 'Chương trình ''Rehabilitation'' trong hệ thống nhà tù có chức năng gì?', 'multiple_choice', '["Tra tấn tù nhân.","Cải tạo, phục hồi nhân phẩm và dạy nghề cho phạm nhân để họ tái hòa nhập cộng đồng sau khi ra tù.","Giam giữ chung thân.","Buộc tội nhân nộp phạt."]', 'Cải tạo, phục hồi nhân phẩm và dạy nghề cho phạm nhân để họ tái hòa nhập cộng đồng sau khi ra tù.', 'Trái ngược với việc chỉ trừng phạt (punishment), các nước phát triển chú trọng vào ''rehabilitation'' để giảm tỷ lệ tái phạm (reoffending rate).'),
('9bfacf02-15d0-4ebd-91af-362cfbff91c0', 'Khái niệm ''Cultural heritage'' (Di sản văn hóa) bao gồm những gì?', 'multiple_choice', '["Chỉ bao gồm các di tích lịch sử bằng đá.","Những giá trị, phong tục, nghệ thuật, và công trình lịch sử được truyền lại từ các thế hệ trước cho thế hệ tương lai.","Những bộ phim mới được sản xuất năm nay.","Văn hóa của người ngoài hành tinh."]', 'Những giá trị, phong tục, nghệ thuật, và công trình lịch sử được truyền lại từ các thế hệ trước cho thế hệ tương lai.', 'Bảo tồn di sản văn hóa (Preserving cultural heritage) là nhiệm vụ sống còn trong kỷ nguyên toàn cầu hóa.'),
('9bfacf02-15d0-4ebd-91af-362cfbff91c0', 'Trường phái ''Abstract art'' (Nghệ thuật trừu tượng) có đặc điểm gì?', 'multiple_choice', '["Vẽ lại một bức ảnh giống hệt thực tế 100%.","Sử dụng màu sắc, hình khối và đường nét để biểu đạt cảm xúc và ý tưởng mà không mô tả chính xác hay rõ ràng các vật thể trong thế giới thực.","Chỉ sử dụng màu đen và trắng.","Chỉ vẽ phong cảnh thiên nhiên."]', 'Sử dụng màu sắc, hình khối và đường nét để biểu đạt cảm xúc và ý tưởng mà không mô tả chính xác hay rõ ràng các vật thể trong thế giới thực.', 'Nghệ thuật trừu tượng đòi hỏi người xem phải có trí tưởng tượng phong phú để tự giải mã ý nghĩa của bức tranh.'),
('9bfacf02-15d0-4ebd-91af-362cfbff91c0', 'Tính từ ''Aesthetic'' (Thuộc về thẩm mỹ) liên quan đến việc đánh giá điều gì?', 'multiple_choice', '["Đánh giá tính năng kỹ thuật của một chiếc máy.","Đánh giá cái đẹp, giá trị nghệ thuật và sự thưởng thức cái đẹp.","Đánh giá đạo đức con người.","Đánh giá giá trị bằng tiền mặt."]', 'Đánh giá cái đẹp, giá trị nghệ thuật và sự thưởng thức cái đẹp.', 'Ví dụ: ''The building has little aesthetic appeal'' (Tòa nhà đó không có nhiều sức hấp dẫn về mặt thẩm mỹ).'),
('f4032265-c05e-4c01-b6f3-fce58f831014', 'Khi đi du lịch ''Off the beaten track'' (Tránh xa lối mòn), bạn sẽ trải nghiệm điều gì?', 'multiple_choice', '["Đi đến các thành phố du lịch đông đúc nhất thế giới.","Đi đến những vùng sâu vùng xa, hoang sơ, ít người biết đến và không bị thương mại hóa.","Đi du lịch bằng xe lửa tốc độ cao.","Chỉ đi dạo trong trung tâm thương mại."]', 'Đi đến những vùng sâu vùng xa, hoang sơ, ít người biết đến và không bị thương mại hóa.', 'Đây là idiom hoàn hảo để miêu tả xu hướng du lịch khám phá của giới trẻ, tránh xa sự xô bồ (hustle and bustle) của đô thị.'),
('f4032265-c05e-4c01-b6f3-fce58f831014', 'Collocation ''An influx of tourists'' có nghĩa là gì?', 'multiple_choice', '["Sự vắng bóng của khách du lịch.","Sự đổ bộ, ồ ạt kéo đến của một số lượng khổng lồ khách du lịch vào một khu vực.","Một tai nạn giao thông liên quan đến du lịch.","Sự quản lý du lịch chặt chẽ."]', 'Sự đổ bộ, ồ ạt kéo đến của một số lượng khổng lồ khách du lịch vào một khu vực.', 'Sự đổ bộ này (influx) thường mang lại lợi ích kinh tế (economic boost) nhưng lại phá hủy môi trường địa phương (environmental degradation).'),
('f4032265-c05e-4c01-b6f3-fce58f831014', 'Mô hình ''Ecotourism'' (Du lịch sinh thái) đặt nguyên tắc nào lên hàng đầu?', 'multiple_choice', '["Xây dựng các khách sạn 5 sao sang trọng giữa rừng.","Khám phá tự nhiên nhưng phải giảm thiểu tối đa tác động xấu đến môi trường sinh thái và hỗ trợ cộng đồng bản địa.","Săn bắt các loài thú quý hiếm.","Tổ chức các lễ hội âm nhạc ồn ào."]', 'Khám phá tự nhiên nhưng phải giảm thiểu tối đa tác động xấu đến môi trường sinh thái và hỗ trợ cộng đồng bản địa.', 'Ecotourism là giải pháp ''sustainable'' (bền vững) cho ngành công nghiệp không khói.'),
('71b58ba2-4598-4aa8-bf29-cde3de7bf89c', 'Thuật ngữ ''Censorship'' (Sự kiểm duyệt) của chính phủ đối với truyền thông nghĩa là gì?', 'multiple_choice', '["Việc cung cấp internet miễn phí cho người dân.","Hành động kiểm soát, ngăn chặn hoặc xóa bỏ các thông tin, sách báo, tin tức được cho là nhạy cảm, độc hại hoặc đi ngược lại lợi ích của nhà nước.","Việc sản xuất các chương trình truyền hình thực tế.","Việc phỏng vấn người dân trên đường phố."]', 'Hành động kiểm soát, ngăn chặn hoặc xóa bỏ các thông tin, sách báo, tin tức được cho là nhạy cảm, độc hại hoặc đi ngược lại lợi ích của nhà nước.', 'Censorship luôn là trung tâm của các cuộc tranh luận về ''Freedom of speech'' (Quyền tự do ngôn luận).'),
('71b58ba2-4598-4aa8-bf29-cde3de7bf89c', 'Khái niệm ''Mass media'' (Phương tiện truyền thông đại chúng) bao gồm những kênh nào?', 'multiple_choice', '["Chỉ những bức thư tay viết cá nhân.","Tất cả các công cụ truyền đạt thông tin (như Báo chí, TV, Radio, Internet) có khả năng tiếp cận một lượng khán giả khổng lồ cùng lúc.","Những cuộc họp kín của chính phủ.","Tin nhắn SMS cá nhân."]', 'Tất cả các công cụ truyền đạt thông tin (như Báo chí, TV, Radio, Internet) có khả năng tiếp cận một lượng khán giả khổng lồ cùng lúc.', 'Mass media có sức mạnh định hình dư luận xã hội (shaping public opinion) vô cùng to lớn.'),
('71b58ba2-4598-4aa8-bf29-cde3de7bf89c', 'Hiện tượng ''Biased reporting'' trong báo chí bị lên án vì lý do gì?', 'multiple_choice', '["Vì bài báo được viết quá ngắn.","Vì việc đưa tin thiếu khách quan, bị bóp méo, thiên vị cho một phe phái hoặc tổ chức nhằm thao túng nhận thức của người đọc.","Vì bài báo không có hình ảnh màu sắc.","Vì giá tờ báo quá đắt."]', 'Vì việc đưa tin thiếu khách quan, bị bóp méo, thiên vị cho một phe phái hoặc tổ chức nhằm thao túng nhận thức của người đọc.', 'Báo chí có đạo đức phải tuân thủ tính ''Objective'' (khách quan). Biased reporting là hành vi phi đạo đức, thường dẫn đến ''fake news''.');